import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"个股公告与讨论","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/announcements.md","filePath":"zh-CN/market-data/announcements.md"}'),i={name:"market-data/announcements.md"};function o(d,a,n,h,s,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="个股公告与讨论" tabindex="-1">个股公告与讨论 <a class="header-anchor" href="#个股公告与讨论" aria-label="Permalink to &quot;个股公告与讨论&quot;">​</a></h1><p>个股详情页提供「资讯」「讨论」「公告」三个 Tab，聚合了与该股票相关的公司公告、社区讨论和市场资讯，帮助投资者快速掌握最新动态。</p><p>入口：长桥 App - 个股详情页 - 顶部 Tab 切换</p><h2 id="公告-tab" tabindex="-1">公告 Tab <a class="header-anchor" href="#公告-tab" aria-label="Permalink to &quot;公告 Tab&quot;">​</a></h2><p>展示上市公司发布的官方公告，按时间倒序排列。</p><h3 id="公司日程" tabindex="-1">公司日程 <a class="header-anchor" href="#公司日程" aria-label="Permalink to &quot;公司日程&quot;">​</a></h3><p>独立模块，汇总近期重要事项提醒，包括：</p><ul><li><strong>财报发布</strong>：预计财报披露日期及对应财季（如「2026 财年第 1 季度业绩披露」）</li><li><strong>分配方案</strong>：派息安排，显示每股派息金额及币种</li><li><strong>登记日 / 除权日</strong>：分红相关关键日期</li></ul><h3 id="公告分类筛选" tabindex="-1">公告分类筛选 <a class="header-anchor" href="#公告分类筛选" aria-label="Permalink to &quot;公告分类筛选&quot;">​</a></h3><p>公告列表支持按类型筛选，分类包括：</p><table tabindex="0"><thead><tr><th>分类</th><th>说明</th></tr></thead><tbody><tr><td>全部</td><td>显示所有类型公告</td></tr><tr><td>重大事项</td><td>重大合同、人事变动、重组并购等</td></tr><tr><td>财务报告</td><td>年报、中报、季报等财务披露</td></tr><tr><td>交易相关</td><td>股票回购、增减持、配股等</td></tr><tr><td>上市文件</td><td>招股书、上市资料等</td></tr></tbody></table><p>每条公告显示发布日期和公告标题，点击可查看原文。</p><h2 id="讨论-tab" tabindex="-1">讨论 Tab <a class="header-anchor" href="#讨论-tab" aria-label="Permalink to &quot;讨论 Tab&quot;">​</a></h2><p>聚合长桥社区中关于该股票的讨论内容。</p><h3 id="涨跌预测" tabindex="-1">涨跌预测 <a class="header-anchor" href="#涨跌预测" aria-label="Permalink to &quot;涨跌预测&quot;">​</a></h3><p>页面顶部展示社区涨跌投票情况：</p><ul><li>显示「猜涨」和「猜跌」的当前比例（如猜跌 88%、猜涨 12%）</li><li>可参与投票，表达对该股短期走势的判断</li><li>显示奖池金额及开奖倒计时</li></ul><h3 id="关注与表态" tabindex="-1">关注与表态 <a class="header-anchor" href="#关注与表态" aria-label="Permalink to &quot;关注与表态&quot;">​</a></h3><p>显示该股票的关注人数和社区表态总数（如「56.1k 人关注 · 2.4k 条表态」），反映该股的社区热度。</p><h3 id="帖子列表" tabindex="-1">帖子列表 <a class="header-anchor" href="#帖子列表" aria-label="Permalink to &quot;帖子列表&quot;">​</a></h3><p>支持按「最新」和「热门」切换排序。每条帖子显示：</p><ul><li>发帖人昵称及身份标签（如「评论员」「收益排行」等特殊标识）</li><li>发帖时间</li><li>帖子正文（超长内容折叠显示，点击「展开」查看全文）</li><li>帖子中可包含@提及的股票代码，点击可跳转至对应个股页面</li></ul><h3 id="达人视图" tabindex="-1">达人视图 <a class="header-anchor" href="#达人视图" aria-label="Permalink to &quot;达人视图&quot;">​</a></h3><p>切换至「达人视图」可单独查看认证达人、评论员发布的内容，过滤普通用户帖子，聚焦高质量分析。</p><h2 id="资讯-tab" tabindex="-1">资讯 Tab <a class="header-anchor" href="#资讯-tab" aria-label="Permalink to &quot;资讯 Tab&quot;">​</a></h2><p>聚合来自各大财经媒体和资讯平台的新闻报道。</p><p>每条资讯显示：</p><ul><li>新闻标题（含中英文来源）</li><li>来源媒体名称（如虎嗅、新浪财经、金融界、Tip Ranks 等）</li><li>发布时间（如「1 小时前」「37 分钟前」）</li></ul><p>资讯内容涵盖：公司最新动态、行业分析报告、机构评级调整、市场异动速递等与该股票相关的信息。</p>',29)])])}const c=t(i,[["render",o]]);export{u as __pageData,c as default};
